#include <stdio.h>
#include <stdlib.h>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int count_divisors(int n) {
    int count = 0;
    for (int i = 1; i * i <= n; i++) {
        if (n % i == 0) {
            if (i * i == n) count++;
            else count += 2;
        }
    }
    return count;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int** M = (int**)malloc(N * sizeof(int*));
        for (int i = 0; i < N; i++) {
            M[i] = (int*)malloc(N * sizeof(int));
            for (int j = 0; j < N; j++) {
                scanf("%d", &M[i][j]);
            }
        }
        int* labels = (int*)malloc(N * sizeof(int));
        for (int i = 1; i <= N; i++) {
            labels[0] = i;
            for (int j = 1; j < N; j++) {
                for (int k = 1; k <= N; k++) {
                    int count = 0;
                    for (int l = 1; l <= k; l++) {
                        if (k % l == 0 && labels[j - 1] % l == 0) count++;
                    }
                    if (count == M[j - 1][0]) {
                        labels[j] = k;
                        break;
                    }
                }
            }
            int valid = 1;
            for (int j = 0; j < N; j++) {
                for (int k = j + 1; k < N; k++) {
                    int count = 0;
                    for (int l = 1; l <= labels[j]; l++) {
                        if (labels[j] % l == 0 && labels[k] % l == 0) count++;
                    }
                    if (count != M[j][k]) {
                        valid = 0;
                        break;
                    }
                }
                if (!valid) break;
            }
            if (valid) {
                for (int j = 0; j < N; j++) {
                    printf("%d\n", labels[j]);
                }
                break;
            }
        }
        free(labels);
        for (int i = 0; i < N; i++) {
            free(M[i]);
        }
        free(M);
    }
    return 0;
}

